const rows = $input.all();

const telegramItem = $('Telegram Trigger').first().json;
const userMessage = (telegramItem.message && telegramItem.message.text) ? telegramItem.message.text : 'halo';

const BULAN_SHORT = {
  'Jan':0,'Feb':1,'Mar':2,'Apr':3,'Mei':4,'May':4,
  'Jun':5,'Jul':6,'Agu':7,'Aug':7,'Sep':8,
  'Okt':9,'Oct':9,'Nov':10,'Des':11,'Dec':11
};

function parseDate(val) {
  if (!val) return null;
  const s = String(val).trim();
  if (!s || s === '0') return null;
  if (/^\d+(\.\d+)?$/.test(s)) {
    const serial = parseFloat(s);
    if (serial < 1 || serial > 100000) return null; // filter angka tidak wajar
    const base = new Date(Date.UTC(1899, 11, 30));
    return new Date(base.getTime() + serial * 86400000);
  }
  const parts = s.split('-');
  if (parts.length === 3) {
    const d = parseInt(parts[0]);
    const m = BULAN_SHORT[parts[1]];
    const y = parseInt(parts[2]);
    if (!isNaN(d) && m !== undefined && !isNaN(y) && y >= 2020 && y <= 2030) {
      return new Date(Date.UTC(y, m, d));
    }
  }
  return null;
}

function parseAngka(val) {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  return parseInt(String(val).replace(/Rp/g,'').replace(/\./g,'').replace(/,/g,'')) || 0;
}

function parseRoas(val) {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  return parseFloat(String(val).replace(',','.')) || 0;
}

const now = new Date();
const jakartaTime = new Date(now.getTime() + 7 * 60 * 60 * 1000);
const BULAN_PANJANG = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
const HARI_LIST = ['Minggu','Senin','Selasa','Rabu','Kamis','Jumat','Sabtu'];
const todayStr = String(jakartaTime.getUTCDate()).padStart(2,'0') + ' ' + BULAN_PANJANG[jakartaTime.getUTCMonth()] + ' ' + jakartaTime.getUTCFullYear();
const hariIni = HARI_LIST[jakartaTime.getUTCDay()];

const dayOfWeek = jakartaTime.getUTCDay();
const daysSinceMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const seninMs = jakartaTime.getTime() - daysSinceMonday * 86400000;
const seninDate = new Date(seninMs);
const seninStr = String(seninDate.getUTCDate()).padStart(2,'0') + '-' + String(seninDate.getUTCMonth()+1).padStart(2,'0') + '-' + seninDate.getUTCFullYear();

const brands = ['Zaneva', 'Oberbe', 'Besyari', 'Muswim', 'Elyasr'];
const dataRows = [];

for (const item of rows) {
  // === FILTER 1: Tanggal harus valid ===
  const d = parseDate(item.json['TANGGAL']);
  if (!d) continue;

  // === FILTER 2: Minimal ada 1 brand dengan data (omset atau ads > 0) ===
  let adaData = false;
  for (const b of brands) {
    const omset = parseAngka(item.json[b + '-Omset']);
    const ads = parseAngka(item.json[b + '-Ads']);
    if (omset > 0 || ads > 0) { adaData = true; break; }
  }
  if (!adaData) continue;

  const tgl = String(d.getUTCDate()).padStart(2,'0') + '-' + String(d.getUTCMonth()+1).padStart(2,'0') + '-' + d.getUTCFullYear();
  const hariNama = HARI_LIST[d.getUTCDay()];
  const row = { tanggal: tgl, hari: hariNama };

  for (const b of brands) {
    const omset = parseAngka(item.json[b + '-Omset']);
    const ads = parseAngka(item.json[b + '-Ads']);
    const roas = parseRoas(item.json[b + '-ROAS']);
    // Hanya masukkan brand yang ada datanya
    if (omset > 0 || ads > 0) {
      row[b] = { omset, ads, roas };
    }
  }
  dataRows.push(row);
}

const systemPrompt = 'Kamu adalah AI asisten laporan bisnis ZANEVA Group dengan 5 brand: Zaneva, Oberbe, Besyari, Muswim, Elyasr.\n\nHari ini: ' + hariIni + ', ' + todayStr + ' (WIB)\nSenin minggu ini: ' + seninStr + '\n\nDATA PENJUALAN HARIAN (format JSON, tanggal DD-MM-YYYY, hanya baris yang ada datanya):\n' + JSON.stringify(dataRows, null, 2) + '\n\nPenjelasan field per brand:\n- omset: total penjualan bersih (Rupiah, angka mentah)\n- ads: biaya iklan (Rupiah, angka mentah)\n- roas: ROAS dari sheet (sudah dihitung, boleh pakai langsung)\n- Brand tidak muncul di suatu hari = tidak ada data untuk hari itu\n\nKEMAMPUAN:\n1. Omset saja — tanggal/range tertentu, satu atau semua brand\n2. Performa lengkap — omset + ads + ROAS per brand\n3. Range tanggal — total periode + rata-rata harian\n4. Ranking brand — by ROAS atau by omset\n5. Perbandingan antar periode (misal bulan ini vs bulan lalu)\n6. Shortcut: hari ini, kemarin, minggu ini (Senin s/d hari ini)\n\nRUMUS KALKULASI RANGE:\n- ROAS Periode = Total Omset range dibagi Total Ads range\n- Rata-rata ROAS Harian = rata-rata dari nilai roas tiap hari\n- Tampilkan KEDUANYA jika range lebih dari 1 hari\n\n=== FORMAT JAWABAN WAJIB ===\n\nLARANGAN KERAS:\n- JANGAN pakai tabel markdown dengan simbol pipe untuk kolom\n- JANGAN pakai garis pemisah tanda minus (----)\n- Format yang tidak bisa dibaca di Telegram DILARANG\n\nFORMAT OMSET SAJA (1 hari):\n[emoji] *Omset [Brand] - [Tgl]*\nRp56.616.324\n\nFORMAT OMSET (range atau semua brand):\n[emoji] *Omset [Brand/Semua Brand]*\n[tgl-awal] - [tgl-akhir]\n\n[tgl] ([Hari])\n[Brand]: RpXXX\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n*Total: RpXXX*\n\nFORMAT PERFORMA LENGKAP (1 hari):\n[emoji] *Performa [Brand/Semua] - [Tgl]*\n\n[Brand]\n\u2514 Omset: RpXXX\n\u2514 Ads: RpXXX\n\u2514 ROAS: X,XX\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n*Total Omset: RpXXX*\n*Total Ads: RpXXX*\nROAS Periode: X,XX\n\nFORMAT PERFORMA LENGKAP (range tanggal):\n[emoji] *Performa [Brand/Semua]*\n[tgl-awal] - [tgl-akhir]\n\n*[tgl] ([Hari])*\n[Brand]: Rp[omset] | Ads Rp[ads] | ROAS [x,xx]\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n*Total: Rp[omset] | Ads Rp[ads]*\nROAS Periode: X,XX | Rata-rata: X,XX\n\nFORMAT RANKING:\n[emoji] *Ranking Brand - [periode]*\n\n\ud83e\udd47 Zaneva - ROAS X,XX | Omset RpXXX\n\ud83e\udd48 Oberbe - ROAS X,XX | Omset RpXXX\n\ud83e\udd49 Besyari - ROAS X,XX | Omset RpXXX\n\nATURAN TAMBAHAN:\n- Format Rupiah: Rp56.616.324 (titik ribuan, tanpa desimal)\n- Format ROAS: 6,31 (koma desimal, 2 angka)\n- Bahasa Indonesia santai tapi profesional\n- Langsung ke data, tidak perlu kalimat pembuka';

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  max_tokens: 1000,
  temperature: 0.3,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
});

return [{ json: { body: body } }];

const response = $input.first().json;

let reply = '';

if (response.choices && response.choices.length > 0 && response.choices[0].message) {
  reply = response.choices[0].message.content || '';
}

if (!reply) {
  if (response.error) {
    reply = '⚠️ Error: ' + (response.error.message || JSON.stringify(response.error));
  } else {
    reply = '⚠️ Maaf, tidak bisa memproses pertanyaan. Coba lagi ya.';
  }
}

return [{ json: { reply: reply } }];
